def default_test():
    savings_account = SavingsAccount(account_number="12345678", balance=1000, overdraft_limit=500, interest_rate=0.05)
    print(savings_account.account_number)
    print(savings_account.balance)
    print(savings_account.overdraft_limit)
    savings_account.apply_interest()
    print(savings_account.balance)
